import {
  apiDocs,
  apiMeta,
  blogCollection,
  changelogCollection,
  docs,
  integrationsCollection,
  legalCollection,
  meta,
} from "fumadocs-mdx:collections/server";
import { loader, multiple } from "fumadocs-core/source";
import { toFumadocsSource } from "fumadocs-mdx/runtime/server";
import { openapiSource } from "fumadocs-openapi/server";
import type { ApiPageProps } from "fumadocs-openapi/ui";
import { openapi } from "~/app/(app)/(content)/_lib/openapi";

// Docs source (general documentation)
const docsSource = loader({
  baseUrl: "/docs",
  source: toFumadocsSource(docs, meta),
});

// API source (API reference documentation)
// Combines manual MDX pages (getting-started, sdks-tools) with virtual OpenAPI endpoint pages
const apiSource = loader({
  baseUrl: "/docs/api-reference",
  source: multiple({
    mdx: toFumadocsSource(apiDocs, apiMeta),
    openapi: await openapiSource(openapi, {
      // Use operationId for flat URLs (no tag folders)
      // This generates /docs/api-reference/search, /docs/api-reference/contents, etc.
      groupBy: "none",
      per: "operation",
    }),
  }),
});

/**
 * Type helpers that properly infer the full collection entry type including DocData.
 *
 * These types provide access to runtime properties (body, toc, structuredData) that
 * are added by fumadocs-mdx v14 but lost in fumadocs-core v16 loader type inference.
 */

/** Full collection entry type for API MDX pages (includes body, toc, structuredData) */
export type ApiPageType = (typeof apiDocs)[number];

/**
 * Frontmatter type for general docs pages, derived directly from the collection type.
 * The collection entry IS the data object (no nested `.data`), matching how ApiPageType
 * is used: `page.data as DocsFrontmatter`.
 * Eliminates the need for a manually-maintained mirror interface.
 */
export type DocsFrontmatter = (typeof docs)[number];

/**
 * Type guard for fumadocs-openapi virtual pages.
 *
 * OpenAPI virtual pages expose `getAPIPageProps()` on their data object.
 * MDX pages expose `body`, `toc`, `structuredData` instead.
 *
 * Use this guard whenever you need to branch between OpenAPI and MDX pages
 * instead of repeating the inline duck-type check.
 */
interface OpenAPIPageData {
  description?: string;
  // ApiPageProps is exported from fumadocs-openapi/ui — no `any` needed
  getAPIPageProps: () => ApiPageProps;
  title?: string;
}

export function isOpenAPIPage(page: {
  data: unknown;
}): page is { data: OpenAPIPageData } {
  const data = page.data as Record<string, unknown>;
  return typeof data?.getAPIPageProps === "function";
}

// Export docs methods
export const { getPage, getPages, pageTree } = docsSource;

// Export API methods with different names
export const {
  getPage: getApiPage,
  getPages: getApiPages,
  pageTree: apiPageTree,
} = apiSource;

// --- Blog ---
const blogSource = loader({
  baseUrl: "/blog",
  source: toFumadocsSource(blogCollection, []),
});

export const getBlogPage = (slugs: string[]) => blogSource.getPage(slugs);
export const getBlogPages = () => blogSource.getPages();

// --- Changelog ---
const changelogSource = loader({
  baseUrl: "/changelog",
  source: toFumadocsSource(changelogCollection, []),
});

export const getChangelogPage = (slugs: string[]) =>
  changelogSource.getPage(slugs);
export const getChangelogPages = () => changelogSource.getPages();

// --- Legal ---
const legalSource = loader({
  baseUrl: "/legal",
  source: toFumadocsSource(legalCollection, []),
});

export const getLegalPage = (slugs: string[]) => legalSource.getPage(slugs);
export const getLegalPages = () => legalSource.getPages();

// --- Integrations ---
const integrationsSource = loader({
  baseUrl: "/integrations",
  source: toFumadocsSource(integrationsCollection, []),
});

export const getIntegrationPage = (slugs: string[]) =>
  integrationsSource.getPage(slugs);
export const getIntegrationPages = () => integrationsSource.getPages();

import { Button } from "@repo/ui/components/ui/button";
import type { GraphContext } from "@vendor/seo/json-ld";
import { JsonLd } from "@vendor/seo/json-ld";
import type { Metadata, Route } from "next";
import Image from "next/image";
import { getBlogPages } from "~/app/(app)/(content)/_lib/source";
import { NavLink } from "~/components/nav-link";
import {
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "~/lib/builders";
import { createMetadata } from "~/lib/content-seo";
import { BlogListingHeader } from "./_components/blog-listing-header";

export const dynamic = "force-static";

const PAGE_TITLE = "Blog";
const PAGE_DESCRIPTION =
  "Engineering deep-dives, product updates, and lessons from building the superintelligence layer for founders at Lightfast.";
const PAGE_URL = "https://lightfast.ai/blog";
const FAQ = [
  {
    question: "What topics does the Lightfast blog cover?",
    answer:
      "We cover engineering deep-dives on AI agent orchestration, product launches and changelogs, company updates, tutorials for integrating with Lightfast, and research on MCP tools and agent memory.",
  },
];

export const metadata: Metadata = createMetadata({
  title: `${PAGE_TITLE} | Lightfast`,
  description: PAGE_DESCRIPTION,
  keywords: [
    "lightfast blog",
    "ai engineering blog",
    "agent infrastructure",
    "mcp tools",
    "product updates",
  ],
  alternates: {
    canonical: PAGE_URL,
    types: {
      "application/rss+xml": [
        { url: "https://lightfast.ai/blog/rss.xml", title: "RSS 2.0" },
      ],
      "application/atom+xml": [
        { url: "https://lightfast.ai/blog/atom.xml", title: "Atom 1.0" },
      ],
    },
  },
  openGraph: {
    title: "Lightfast Blog – Operating Infrastructure for Agents and Apps",
    description:
      "Articles on operating infrastructure, event-driven architecture, and agent tooling.",
    type: "website",
    url: PAGE_URL,
    siteName: "Lightfast",
    locale: "en_US",
  },
  twitter: {
    card: "summary_large_image",
    title: "Lightfast Blog",
    description: PAGE_DESCRIPTION,
    site: "@lightfastai",
    creator: "@lightfastai",
  },
});

export default function BlogPage() {
  const pages = getBlogPages();

  const sortedPages = [...pages].sort((a, b) => {
    return (
      new Date(b.data.publishedAt).getTime() -
      new Date(a.data.publishedAt).getTime()
    );
  });

  const [latest, ...restPages] = sortedPages;
  const featured = latest?.data.featuredImage ? latest : null;
  const listPages = featured ? restPages : sortedPages;

  const structuredData: GraphContext = {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      {
        "@type": "Blog" as const,
        "@id": `${PAGE_URL}#blog`,
        url: PAGE_URL,
        name: "Lightfast Blog",
        description: PAGE_DESCRIPTION,
        publisher: { "@id": "https://lightfast.ai/#organization" },
        blogPost: sortedPages.slice(0, 10).map((page) => ({
          "@type": "BlogPosting" as const,
          headline: page.data.title,
          description: page.data.description,
          url: `https://lightfast.ai/blog/${page.slugs[0]}`,
          datePublished: page.data.publishedAt,
        })),
      },
      buildFaqEntity(FAQ, PAGE_URL),
    ],
  };

  return (
    <>
      <JsonLd code={structuredData} />
      <BlogListingHeader title="Blog" />
      {featured?.data.featuredImage && (
        <article className="mb-12" key={featured.slugs[0]}>
          <div className="relative aspect-video w-full overflow-hidden rounded-lg bg-card">
            <Image
              alt={featured.data.title}
              className="h-full w-full object-cover"
              fill
              src={featured.data.featuredImage}
            />
          </div>
          <h2 className="mt-6 font-medium font-pp text-2xl">
            <Button
              asChild
              className="h-auto p-0 font-medium font-pp text-2xl"
              variant="link"
            >
              <NavLink href={`/blog/${featured.slugs[0]}` as Route}>
                {featured.data.title}
              </NavLink>
            </Button>
          </h2>
          <p className="mt-2 text-muted-foreground text-sm">
            <time dateTime={featured.data.publishedAt}>
              {new Date(featured.data.publishedAt).toLocaleDateString("en-US", {
                year: "numeric",
                month: "short",
                day: "numeric",
              })}
            </time>
          </p>
        </article>
      )}
      <div className="space-y-2">
        {sortedPages.length === 0 ? (
          <div className="rounded-xs bg-accent/40 p-4">
            <h2 className="mb-4 font-semibold text-sm">Coming soon</h2>
            <p className="text-muted-foreground text-sm leading-relaxed">
              We're preparing news and updates about Lightfast. Check back soon
              for product announcements, feature releases, and insights from the
              Lightfast team.
            </p>
          </div>
        ) : (
          listPages.map((page) => (
            <article
              className="rounded-xs bg-accent/40 p-4 transition-colors hover:bg-accent"
              key={page.slugs[0]}
            >
              <NavLink
                className="block"
                href={`/blog/${page.slugs[0]}` as Route}
              >
                <h2 className="mb-1 font-base text-md">
                  {page.data.title}
                </h2>
                <p className="mb-4 text-muted-foreground text-sm leading-relaxed">
                  {page.data.description}
                </p>
                <div className="flex items-center gap-2 text-muted-foreground text-sm">
                  <span className="capitalize">{page.data.category}</span>
                  <span>·</span>
                  <time dateTime={page.data.publishedAt}>
                    {new Date(page.data.publishedAt).toLocaleDateString(
                      "en-US",
                      { year: "numeric", month: "short", day: "numeric" },
                    )}
                  </time>
                </div>
              </NavLink>
            </article>
          ))
        )}
      </div>
    </>
  );
}

import { z } from "zod";

// Mirror of providerSlugSchema from @repo/app-providers/client. Inlined because
// fumadocs-mdx's build-time loader can't resolve the package's extensionless
// re-exports under Node ESM. Keep in sync with packages/app-providers/src/client/display.ts.
const providerSlugSchema = z.enum([
  "apollo",
  "github",
  "vercel",
  "linear",
  "sentry",
]);

const AuthorSchema = z.object({
  name: z.string().min(1),
  url: z.url(),
  twitterHandle: z.string().min(1),
  jobTitle: z.string().min(1).optional(),
});

const FaqItemSchema = z.object({
  question: z.string().min(10),
  answer: z.string().min(20),
});

const HowToStepSchema = z.object({
  name: z.string().min(1),
  text: z.string().min(20),
  url: z.url().optional(),
});

const BasePageSchema = z.object({
  title: z.string().min(1),
  description: z.string().min(50).max(160),
  keywords: z.array(z.string().min(1)).min(3).max(20),
  canonicalUrl: z.url(),
  ogTitle: z.string().min(1).max(70),
  ogDescription: z.string().min(50).max(160),
  noindex: z.boolean().default(false),
  nofollow: z.boolean().default(false),
});

const ContentPageSchema = BasePageSchema.extend({
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  faq: z.array(FaqItemSchema).min(1),
  featuredImage: z.string().startsWith("/images/").optional(),
});

export const BlogPostSchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/blog/"))
    .optional(),
  category: z.enum([
    "engineering",
    "product",
    "company",
    "tutorial",
    "research",
  ]),
  readingTimeMinutes: z.number().int().min(1),
  featured: z.boolean().default(false),
  tldr: z.string().min(20).max(300),
  howToSteps: z.array(HowToStepSchema).min(2).optional(),
});

export const ChangelogEntrySchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/changelog/"))
    .optional(),
  version: z.string().min(1),
  type: z.enum(["feature", "improvement", "fix", "breaking"]),
  tldr: z.string().min(20).max(300),
  improvements: z.array(z.string().min(1)).optional(),
});

export const LegalPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/legal/"))
    .optional(),
  updatedAt: z.iso.datetime(),
  effectiveAt: z.iso.datetime(),
});

const IntegrationStatusSchema = z.enum(["live", "beta", "planned"]);
const IntegrationCategorySchema = z.enum([
  "dev-tools",
  "monitoring",
  "comms",
  "data",
  "project-management",
]);

// Mirror of IntegrationLogoIcons keys from @repo/ui/integration-icons. Inlined
// because fumadocs-mdx's build-time loader can't resolve TSX component exports
// under Node ESM. Keep in sync with packages/ui/src/components/integration-icons.tsx.
const integrationIconKeySchema = z.enum([
  "apollo",
  "airtable",
  "claude",
  "codex",
  "datadog",
  "discord",
  "github",
  "linear",
  "notion",
  "posthog",
  "sentry",
  "slack",
  "vercel",
  "circleci",
  "pagerduty",
  "intercom",
  "hubspot",
  "stripe",
  "grafana",
  "clerk",
  "jira",
  "mixpanel",
  "zendesk",
  "cloudflare",
  "supabase",
  "resend",
  "typeform",
  "cal-com",
  "better-stack",
  "loops",
  "segment",
  "statsig",
  "launchdarkly",
  "amplitude",
  "gong",
  "outreach",
  "instantly",
  "incident-io",
  "plain",
  "attio",
  "neon",
  "customer-io",
  "fireflies",
  "workos",
]);

const BaseIntegrationSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/integrations/"))
    .optional(),
  iconKey: integrationIconKeySchema,
  tagline: z.string().min(10).max(120),
  category: IntegrationCategorySchema,
  faq: z.array(FaqItemSchema).min(1).optional(),
  updatedAt: z.iso.datetime(),
});

const IntegrationPageLiveSchema = BaseIntegrationSchema.extend({
  status: z.literal("live"),
  providerId: providerSlugSchema,
  featuredImage: z.string().startsWith("/images/"),
  docsUrl: z.string().startsWith("/docs/"),
});

const IntegrationPageBetaSchema = BaseIntegrationSchema.extend({
  status: z.literal("beta"),
  providerId: providerSlugSchema,
  featuredImage: z.string().startsWith("/images/").optional(),
  docsUrl: z.string().startsWith("/docs/").optional(),
});

const IntegrationPagePlannedSchema = BaseIntegrationSchema.extend({
  status: z.literal("planned"),
  featuredImage: z.string().startsWith("/images/").optional(),
});

export const IntegrationPageSchema = z.discriminatedUnion("status", [
  IntegrationPageLiveSchema,
  IntegrationPageBetaSchema,
  IntegrationPagePlannedSchema,
]);

export const DocsPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/docs/"))
    .optional(),
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  proficiencyLevel: z
    .enum(["Beginner", "Intermediate", "Advanced", "Expert"])
    .optional(),
});

// Inferred TypeScript types
export type BlogPostData = z.infer<typeof BlogPostSchema>;
export type ChangelogEntryData = z.infer<typeof ChangelogEntrySchema>;
export type LegalPageData = z.infer<typeof LegalPageSchema>;
export type DocsPageData = z.infer<typeof DocsPageSchema>;
export type IntegrationPageData = z.infer<typeof IntegrationPageSchema>;
export type IntegrationCategory = IntegrationPageData["category"];
export type IntegrationStatus = IntegrationPageData["status"];

// Fields required by the SEO layer — satisfied structurally by BlogPostData,
// ChangelogEntryData, and DocsPageData. Derived from BlogPostData so schema
// renames propagate here automatically.
export type ContentSeoData = Pick<
  BlogPostData,
  | "authors"
  | "description"
  | "keywords"
  | "nofollow"
  | "noindex"
  | "ogDescription"
  | "ogTitle"
  | "publishedAt"
  | "title"
  | "updatedAt"
>;

// Derived from Zod — Zod is the sole source of truth for these unions
export type BlogCategory = BlogPostData["category"];
// → "engineering" | "product" | "company" | "tutorial" | "research"

export type ChangelogType = ChangelogEntryData["type"];
// → "feature" | "improvement" | "fix" | "breaking"

import { Button } from "@repo/ui/components/ui/button";
import type {
  FAQPage,
  GraphContext,
  Organization,
  Question,
  SoftwareApplication,
  WebSite,
} from "@vendor/seo/json-ld";
import { JsonLd } from "@vendor/seo/json-ld";
import { Link as MicrofrontendLink } from "@vercel/microfrontends/next/client";
import type { Metadata } from "next";
import { ChangelogPreview } from "~/app/(app)/_components/changelog-preview";
import { FAQSection, faqs } from "~/app/(app)/_components/faq-section";
import { HeroChangelogBadge } from "~/app/(app)/_components/hero-changelog-badge";
import { WaitlistCTA } from "~/app/(app)/_components/waitlist-cta";
import {
  HAIRLINE_BOTTOM_X_PCT,
  HAIRLINE_X_PCT,
  HAIRLINE_Y_PCT,
  IsometricHero,
} from "./_components/isometric-hero";
import { FlowField } from "./_components/flow-field";

