      </div>
      <div className="mt-4 flex items-center gap-2">
        <TypeBadge kind={item.kind} />
        <time className="text-muted-foreground text-sm">
          {formatDate(item.page.data.publishedAt)}
        </time>
      </div>
      <h3 className="mt-2 line-clamp-2 font-medium font-pp text-2xl text-foreground tracking-tight">
        {item.page.data.title}
      </h3>
    </NavLink>
  );
}

function SquareCard({ item }: { item: FeedItem }) {
  return (
    <NavLink className="group" href={hrefFor(item)}>
      <div className="relative aspect-square w-full overflow-hidden rounded-md border border-border/50 bg-card">
        <ImageOrFallback
          alt={item.page.data.title}
          iconSize="h-6 w-6"
          sizes="(min-width: 1024px) 33vw, 100vw"
