      <div className="grid grid-cols-1 gap-4 lg:grid-cols-3">
        <FeaturedCard item={featured} />
        <div className="flex flex-col gap-4">
          {rest.map((item) => (
            <SquareCard item={item} key={hrefFor(item)} />
          ))}
        </div>
      </div>
    </>
  );
}

